import sqlite3
from typing import List, Dict

def search(filters: List[Dict]) -> List[Dict]:
    # Connect to the database
    conn = sqlite3.connect('example.db')
    
    # Create a list to store the results
    results = []
    
    # Iterate over each filter in the list
    for filter in filters:
        field = filter['field']
        op = filter['op']
        value = filter['value']
        
        # Construct the SQL query based on the user input
        query = f"SELECT * FROM users WHERE {field} {op} ?"
        
        # Execute the query and store the results in the list
